import{_ as l,c as r,o,a5 as i,j as a}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.41：多项修复和改进，中文本地化增强","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.41.md","filePath":"changelog/v1.1.41.md","lastUpdated":1772014034000}'),t={name:"changelog/v1.1.41.md"};function n(h,e,d,s,p,c){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="v1-1-41-多项修复和改进-中文本地化增强" tabindex="-1">v1.1.41：多项修复和改进，中文本地化增强 <a class="header-anchor" href="#v1-1-41-多项修复和改进-中文本地化增强" aria-label="Permalink to “v1.1.41：多项修复和改进，中文本地化增强”">​</a></h1><p><strong>发布日期</strong>：2026年01月29日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新修复了多个问题，改进了中文本地化体验，增强了工具功能和响应性。</p><hr><h2 id="问题修复-kimi-k2-5-模型参数问题" tabindex="-1">问题修复：Kimi K2.5 模型参数问题 <a class="header-anchor" href="#问题修复-kimi-k2-5-模型参数问题" aria-label="Permalink to “问题修复：Kimi K2.5 模型参数问题”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>Kimi K2.5 模型的 maxOutputTokens 参数被错误地硬编码为 undefined，导致在某些推理提供商上出现问题。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>感谢社区贡献者 @ideallove 的修复，现在 maxOutputTokens 参数可以正确设置，Kimi K2.5 模型可以在所有提供商上正常工作。</p><hr><h2 id="问题修复-缓存冲突" tabindex="-1">问题修复：缓存冲突 <a class="header-anchor" href="#问题修复-缓存冲突" aria-label="Permalink to “问题修复：缓存冲突”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>SDK 缓存键没有包含提供商 ID，导致不同提供商之间可能发生缓存冲突。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>感谢社区贡献者 @saba-ch 的修复，现在缓存键包含提供商 ID，确保不同提供商的缓存不会相互干扰。</p><hr><h2 id="问题修复-中文本地化问题" tabindex="-1">问题修复：中文本地化问题 <a class="header-anchor" href="#问题修复-中文本地化问题" aria-label="Permalink to “问题修复：中文本地化问题”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><ul><li>中文标点符号显示不正确</li><li>缺失中文翻译键时会回退到英文</li></ul><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><p>感谢社区贡献者 @MaxMiksa 的修复：</p><ul><li>标点符号现在显示正确</li><li>缺失的中文翻译键已被填充，确保界面完全中文化</li></ul><hr><h2 id="新功能-文件标签改进" tabindex="-1">新功能：文件标签改进 <a class="header-anchor" href="#新功能-文件标签改进" aria-label="Permalink to “新功能：文件标签改进”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><ul><li>文件标签现在会在打开时自动滚动到可见区域</li><li>支持鼠标滚轮滚动文件标签</li></ul><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>当文件标签过多时：</p><ul><li>打开文件会自动滚动到该标签</li><li>使用鼠标滚轮可以快速浏览所有标签</li></ul><hr><h2 id="新功能-abortsignal-支持" tabindex="-1">新功能：AbortSignal 支持 <a class="header-anchor" href="#新功能-abortsignal-支持" aria-label="Permalink to “新功能：AbortSignal 支持”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>Ripgrep.files() 和 GlobTool 现在支持 AbortSignal，可以更好地控制文件搜索操作。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><p>在文件搜索时传递 AbortSignal，可以在需要时取消搜索操作，提高控制能力。</p><hr><h2 id="新功能-音频文件支持" tabindex="-1">新功能：音频文件支持 <a class="header-anchor" href="#新功能-音频文件支持" aria-label="Permalink to “新功能：音频文件支持”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在允许在 Content Security Policy 中使用 data: URL 加载小型音频文件。</p><h3 id="对你的影响" tabindex="-1">对你的影响 <a class="header-anchor" href="#对你的影响" aria-label="Permalink to “对你的影响”">​</a></h3><p>可以在界面中使用音频文件而无需外部服务器，提高自包含性。</p><hr><h2 id="问题修复-设置响应性" tabindex="-1">问题修复：设置响应性 <a class="header-anchor" href="#问题修复-设置响应性" aria-label="Permalink to “问题修复：设置响应性”">​</a></h2><h3 id="之前的问题-3" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-3" aria-label="Permalink to “之前的问题”">​</a></h3><p>在移动端或小屏幕设备上，设置界面的响应性不够好。</p><h3 id="现在的情况-3" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-3" aria-label="Permalink to “现在的情况”">​</a></h3><p>改进了设置界面的响应性，现在在各种屏幕尺寸上都能良好显示。</p><hr><h2 id="问题修复-对话框对齐" tabindex="-1">问题修复：对话框对齐 <a class="header-anchor" href="#问题修复-对话框对齐" aria-label="Permalink to “问题修复：对话框对齐”">​</a></h2><h3 id="之前的问题-4" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-4" aria-label="Permalink to “之前的问题”">​</a></h3><p>对话框中的元素对齐和间距不正确。</p><h3 id="现在的情况-4" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-4" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了对齐和间距问题，对话框现在更加美观和易用。</p><hr><h2 id="问题修复-katex-数学公式" tabindex="-1">问题修复：KaTeX 数学公式 <a class="header-anchor" href="#问题修复-katex-数学公式" aria-label="Permalink to “问题修复：KaTeX 数学公式”">​</a></h2><h3 id="之前的问题-5" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-5" aria-label="Permalink to “之前的问题”">​</a></h3><p>KaTeX 内联数学公式后跟随标点符号时显示异常。</p><h3 id="现在的情况-5" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-5" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了这个问题，数学公式后可以正常跟随标点符号。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 Kimi K2.5 模型</td><td>✅ 强烈推荐（修复关键问题）</td></tr><tr><td>使用中文界面</td><td>✅ 推荐升级（本地化改进）</td></tr><tr><td>使用 Desktop 版</td><td>✅ 推荐升级（多项改进）</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',65),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Ensure variants for Copilot models work with maxTokens being set</li><li>Fixed maxOutputTokens being accidentally hardcoded to undefined which caused kimi-k2.5 issues on some inference providers (@ideallove)</li><li>Include provider ID in SDK cache key to prevent cache collisions (@saba-ch)</li><li>Allow media-src data: URL for small audio files in Content Security Policy (@tanapok)</li><li>Update experimental environment variables in CLI documentation (@bbabou)</li><li>Add ctx.abort to grep tool</li><li>Add AbortSignal support to Ripgrep.files() and GlobTool (@goniz)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Make settings more responsive for mobile and small web/desktop (@DNGriffin)</li><li>Fixed type errors in app package (@Brendonovich)</li><li>Auto scroll to file tabs on open and enable mouse wheel scrolling (@alexyaroshuk)</li><li>Remove duplicate keys causing TypeScript failures (@eXamadeus)</li><li>Normalize Chinese punctuation for Chinese UI (@MaxMiksa)</li><li>Fill missing Chinese translation keys to avoid English fallback (@MaxMiksa)</li><li>Fix alignment and padding in dialogs (@alexyaroshuk)</li></ul><p><strong>Thank you to 12 community contributors:</strong></p><p>@R44VC0RP:</p><ul><li>fix(script): remove highlights template from release notes (#11052)</li></ul><p>@zerone0x:</p><ul><li>fix(ui): allow KaTeX inline math to be followed by punctuation (#11033)</li></ul><p>@alexyaroshuk:</p><ul><li>fix(app): alignment and padding in dialogs (#10866)</li><li>fix(app): file tabs - auto scroll on open &amp; scroll via mouse wheel (#11070)</li></ul><p>@MaxMiksa:</p><ul><li>fix(app): fill missing zh keys to avoid English fallback (#10841)</li><li>fix(opencode): normalize zh punctuation for Chinese UI (#10842)</li><li>fix(ui): improve zh duration display formatting (#10844)</li></ul><p>@goniz:</p><ul><li>fix(opencode): add AbortSignal support to Ripgrep.files() and GlobTool (#10833)</li></ul><p>@eXamadeus:</p><ul><li>fix(typescript errors): remove duplicate keys causing typescript failures (#11071)</li></ul><p>@Brendonovich:</p><ul><li>fix(app): types</li></ul><p>@bbabou:</p><ul><li>docs: update experimental environment variables in CLI docs (#11030)</li></ul><p>@DNGriffin:</p><ul><li>fix(app): make settings more responsive for mobile and small web/desktop (#10775)</li></ul><p>@tanapok:</p><ul><li>fix(opencode): allow media-src data: URL for small audio files (#11082)</li></ul><p>@saba-ch:</p><ul><li>fix(provider): include providerID in SDK cache key (#11020)</li></ul><p>@ideallove:</p><ul><li>fix: maxOutputTokens was accidentally hardcoded to undefined (#10995)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=l(t,[["render",n]]);export{u as __pageData,m as default};
